import{_ as e,o as r,c as a,al as i}from"./chunks/framework.Dmfvx4Xt.js";const h=JSON.parse('{"title":"Probabilistic Programming API","description":"","frontmatter":{},"headers":[],"relativePath":"api/probprog.md","filePath":"api/probprog.md","lastUpdated":null}'),o={name:"api/probprog.md"};function n(s,t,d,c,l,g){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="probprog-api" tabindex="-1">Probabilistic Programming API <a class="header-anchor" href="#probprog-api" aria-label="Permalink to &quot;Probabilistic Programming API {#probprog-api}&quot;">​</a></h1><p>This page is a flat index of the public exports of <code>Reactant.ProbProg</code>, Reactant&#39;s probabilistic-programming module. Names are qualified as <code>ProbProg.&lt;name&gt;</code>; <code>using Reactant: ProbProg</code> unqualifies them.</p><p>For walkthroughs and runnable end-to-end programs, follow the <a href="/Reactant.jl/previews/PR2834/tutorials/probprog/index#probprog">Probabilistic Programming tutorials</a>:</p><ul><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/index#probprog">Overview</a> — Bayesian linear and logistic regression.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/interface-overview#probprog-interface-overview">Interface overview</a> — quick tabular summary of the public surface.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/sampling#probprog-sampling">Sampling and distributions</a> — <code>sample</code>, built-in distributions, custom samplers, supports.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a> — <code>Trace</code>, <code>Address</code>, <code>Constraint</code>, <code>Selection</code>, <code>simulate</code> and <code>generate</code>.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-trace-representation">Trace representation</a> — how Reactant carries a trace as a flat position-vector tensor during compilation, and the helpers that expand it back into a tree-shaped <code>Trace</code>.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#probprog-mcmc">MCMC: MH, HMC, NUTS</a> — <code>mh</code>, <code>mcmc</code>, <code>mcmc_logpdf</code>.</p></li><li><p><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a> — <code>run_chain</code>, <code>MCMCState</code>, checkpointing, <code>mcmc_summary</code>.</p></li></ul><p>The conceptual vocabulary (traces, choice maps, selections, generative functions) is the same as in <a href="https://www.gen.dev/" target="_blank" rel="noreferrer">Gen.jl</a>; readers familiar with Gen can map <code>Constraint</code> onto Gen&#39;s <code>ChoiceMap</code>, <code>select</code> onto <code>Gen.select</code>, and so on.</p><h2 id="Types" tabindex="-1">Types <a class="header-anchor" href="#Types" aria-label="Permalink to &quot;Types {#Types}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">See</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Trace</code></td><td style="text-align:right;"><code>mutable struct Trace; choices, retval, weight, subtraces; end</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>Address</code></td><td style="text-align:right;"><code>Address(syms::Symbol...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>Selection</code></td><td style="text-align:right;"><code>const Selection = OrderedSet{Address}</code>; built via <code>select</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>Constraint</code></td><td style="text-align:right;"><code>Constraint(pairs::Pair...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>MCMCState</code></td><td style="text-align:right;"><code>mutable struct MCMCState; position, gradient, potential_energy, step_size, inverse_mass_matrix, rng; end</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a></td></tr></tbody></table><h2 id="Distributions" tabindex="-1">Distributions <a class="header-anchor" href="#Distributions" aria-label="Permalink to &quot;Distributions {#Distributions}&quot;">​</a></h2><p><code>ProbProg.sample(rng, dist; symbol=:x)</code> works on any <code>Distribution</code> subtype. Built-in distributions (<code>Normal</code>, <code>Exponential</code>, <code>LogNormal</code>, <code>Bernoulli</code>) and the recipe for defining custom ones are described in the <a href="/Reactant.jl/previews/PR2834/tutorials/probprog/sampling#probprog-sampling">Sampling and distributions</a> tutorial.</p><h2 id="Modeling" tabindex="-1">Modeling <a class="header-anchor" href="#Modeling" aria-label="Permalink to &quot;Modeling {#Modeling}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">See</th></tr></thead><tbody><tr><td style="text-align:right;"><code>sample</code></td><td style="text-align:right;"><code>sample(rng, dist; symbol)</code> &amp;nbsp;/&amp;nbsp; <code>sample(rng, f, args...; symbol, logpdf, support, bounds)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/sampling#probprog-sampling">Sampling and distributions</a></td></tr><tr><td style="text-align:right;"><code>untraced_call</code></td><td style="text-align:right;"><code>untraced_call(rng, f, args...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/sampling#probprog-sampling">Sampling and distributions</a></td></tr><tr><td style="text-align:right;"><code>simulate</code></td><td style="text-align:right;"><code>simulate(rng, f, args...) -&gt; (trace_tensor, weight, retval)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>simulate_</code></td><td style="text-align:right;"><code>simulate_(rng, f, args...) -&gt; (trace::Trace, weight)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>generate</code></td><td style="text-align:right;"><code>generate(rng, constraint_tensor, f, args...; constrained_addresses)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>generate_</code></td><td style="text-align:right;"><code>generate_(rng, constraint, f, args...) -&gt; (trace::Trace, weight)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr></tbody></table><h2 id="Inference" tabindex="-1">Inference <a class="header-anchor" href="#Inference" aria-label="Permalink to &quot;Inference {#Inference}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">See</th></tr></thead><tbody><tr><td style="text-align:right;"><code>mh</code></td><td style="text-align:right;"><code>mh(rng, trace, weight, f, args...; selection)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#probprog-mcmc">MCMC: MH, HMC, NUTS</a></td></tr><tr><td style="text-align:right;"><code>mcmc</code></td><td style="text-align:right;"><code>mcmc(rng, original_trace, f, args...; selection, algorithm, step_size, inverse_mass_matrix, num_warmup, num_samples, ...)</code> &amp;nbsp;/&amp;nbsp; <code>mcmc(state::MCMCState, ...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#probprog-mcmc">MCMC: MH, HMC, NUTS</a></td></tr><tr><td style="text-align:right;"><code>mcmc_logpdf</code></td><td style="text-align:right;"><code>mcmc_logpdf(rng, logdensity_fn, initial_position, args...; algorithm, step_size, inverse_mass_matrix, ...)</code> &amp;nbsp;/&amp;nbsp; <code>mcmc_logpdf(state::MCMCState, ...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#probprog-mcmc">MCMC: MH, HMC, NUTS</a></td></tr><tr><td style="text-align:right;"><code>run_chain</code></td><td style="text-align:right;"><code>run_chain(rng, logpdf_fn, initial_position, args...; num_warmup, num_samples, chunk_size, ...)</code> &amp;nbsp;/&amp;nbsp; <code>run_chain(state::MCMCState, ...)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a></td></tr></tbody></table><p>NUTS currently requires an explicit <code>step_size</code>; the default <code>step_size = nothing</code> is rejected by the pass implementation (<code>find_reasonable_step_size</code> is not yet implemented). Pass <code>Reactant.ConcreteRNumber(0.1)</code> (or similar) and rely on dual averaging when <code>adapt_step_size = true</code>.</p><h2 id="State-persistence" tabindex="-1">State persistence <a class="header-anchor" href="#State-persistence" aria-label="Permalink to &quot;State persistence {#State-persistence}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">See</th></tr></thead><tbody><tr><td style="text-align:right;"><code>save_state</code></td><td style="text-align:right;"><code>save_state(filename::String, state::MCMCState)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a></td></tr><tr><td style="text-align:right;"><code>load_state</code></td><td style="text-align:right;"><code>load_state(filename::String) -&gt; MCMCState</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a></td></tr></tbody></table><h2 id="Utilities" tabindex="-1">Utilities <a class="header-anchor" href="#Utilities" aria-label="Permalink to &quot;Utilities {#Utilities}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">See</th></tr></thead><tbody><tr><td style="text-align:right;"><code>select</code></td><td style="text-align:right;"><code>select(addrs::Address...) -&gt; Selection</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>get_choices</code></td><td style="text-align:right;"><code>get_choices(trace::Trace) -&gt; Dict{Symbol,Any}</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>with_trace</code></td><td style="text-align:right;"><code>with_trace(f) -&gt; (f_result, tt)</code> (installs the Impulse tracing context for the duration of <code>f()</code>; collects the layout metadata <code>unflatten_trace</code> needs)</td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>unflatten_trace</code></td><td style="text-align:right;"><code>unflatten_trace(trace_tensor, weight, entries, retval) -&gt; Trace</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>filter_entries_by_selection</code></td><td style="text-align:right;"><code>filter_entries_by_selection(entries, selection)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#probprog-mcmc">MCMC: MH, HMC, NUTS</a></td></tr><tr><td style="text-align:right;"><code>extract_addresses</code></td><td style="text-align:right;"><code>extract_addresses(constraint::Constraint) -&gt; Set{Address}</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#probprog-traces">Traces and constrained inference</a></td></tr><tr><td style="text-align:right;"><code>mcmc_summary</code></td><td style="text-align:right;"><code>mcmc_summary(samples; names)</code> &amp;nbsp;/&amp;nbsp; <code>mcmc_summary(trace::Trace)</code></td><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/chains#probprog-chains">Running and resuming chains</a></td></tr></tbody></table>',18)])])}const b=e(o,[["render",n]]);export{h as __pageData,b as default};
